17: package org.apache.camel.component.timer;
18: 
19: import java.util.Date;
20: import java.util.Timer;
21: 
22: import org.apache.camel.Category;
23: import org.apache.camel.Component;
24: import org.apache.camel.Consumer;
25: import org.apache.camel.LoggingLevel;
26: import org.apache.camel.MultipleConsumersSupport;
27: import org.apache.camel.Processor;
28: import org.apache.camel.Producer;
29: import org.apache.camel.RuntimeCamelException;
30: import org.apache.camel.api.management.ManagedAttribute;
31: import org.apache.camel.api.management.ManagedResource;
32: import org.apache.camel.spi.Metadata;
33: import org.apache.camel.spi.UriEndpoint;
34: import org.apache.camel.spi.UriParam;
35: import org.apache.camel.spi.UriPath;
36: import org.apache.camel.support.DefaultEndpoint;
