38: /**
39:  * Generate messages in specified intervals using <code>java.util.Timer</code>.
40:  *
41:  * This component is similar to the scheduler component, but has much less functionality.
42:  */
43: @ManagedResource(description = "Managed TimerEndpoint")
44: @UriEndpoint(firstVersion = "1.0.0", scheme = "timer", title = "Timer", syntax = "timer:timerName", consumerOnly = true,
45:              remote = false, category = { Category.CORE, Category.SCHEDULING }, headersClass = TimerConstants.class)
46: public class TimerEndpoint extends DefaultEndpoint implements MultipleConsumersSupport {
47:     @UriPath
48:     @Metadata(required = true)
49:     private String timerName;
50:     @UriParam(defaultValue = "1000", javaType = "java.time.Duration")
51:     private long period = 1000;
52:     @UriParam(defaultValue = "1000", javaType = "java.time.Duration")
53:     private long delay = 1000;
54:     @UriParam
55:     private long repeatCount;
56:     @UriParam
57:     private boolean fixedRate;
58:     @UriParam
59:     private boolean includeMetadata;
60:     @UriParam(defaultValue = "TRACE", label = "consumer,scheduler")
61:     private LoggingLevel runLoggingLevel = LoggingLevel.TRACE;
62:     @UriParam(label = "advanced", defaultValue = "true")
63:     private boolean daemon = true;
64:     @UriParam(label = "advanced")
65:     private Date time;
66:     @UriParam(label = "advanced")
67:     private String pattern;
68:     @UriParam(label = "advanced")
69:     private Timer timer;
70:     @UriParam(label = "advanced")
71:     private boolean synchronous;
72: 
73:     public TimerEndpoint() {
74:     }
75: 
76:     public TimerEndpoint(String uri, Component component, String timerName) {
77:         super(uri, component);
78:         this.timerName = timerName;
79:     }
80: 
81:     protected TimerEndpoint(String endpointUri, Component component) {
82:         super(endpointUri, component);
83:     }
84: 
85:     @Override
86:     public boolean isRemote() {
87:         return false;
88:     }
89: 
90:     @Override
91:     public TimerComponent getComponent() {
92:         return (TimerComponent) super.getComponent();
93:     }
94: 
95:     @Override
96:     public Producer createProducer() throws Exception {
97:         throw new RuntimeCamelException("Cannot produce to a TimerEndpoint: " + getEndpointUri());
98:     }
99: 
100:     @Override
101:     public Consumer createConsumer(Processor processor) throws Exception {
102:         Consumer answer = new TimerConsumer(this, processor);
103:         configureConsumer(answer);
104:         return answer;
105:     }
106: 
107:     @Override
108:     protected void doInit() throws Exception {
109:         super.doInit();
110:         if (timerName == null) {
111:             timerName = getEndpointUri();
112:         }
113:         // do nothing in regard to setTimer, the timer will be set when the first consumer requests it
114:     }
115: 
116:     @Override
117:     protected void doStop() throws Exception {
118:         setTimer(null);
119:         super.doStop();
120:     }
121: 
122:     @Override
123:     @ManagedAttribute
124:     public boolean isMultipleConsumersSupported() {
125:         return true;
126:     }
127: 
128:     @ManagedAttribute(description = "Timer Name")
129:     public String getTimerName() {
130:         return timerName;
131:     }
132: 
133:     /**
134:      * The name of the timer
135:      */
136:     @ManagedAttribute(description = "Timer Name")
137:     public void setTimerName(String timerName) {
138:         this.timerName = timerName;
139:     }
140: 
141:     @ManagedAttribute(description = "Timer Daemon")
142:     public boolean isDaemon() {
143:         return daemon;
144:     }
145: 
146:     /**
147:      * Specifies whether the thread associated with the timer endpoint runs as a daemon.
148:      * <p/>
149:      * The default value is true.
150:      */
151:     @ManagedAttribute(description = "Timer Daemon")
152:     public void setDaemon(boolean daemon) {
153:         this.daemon = daemon;
154:     }
155: 
156:     @ManagedAttribute(description = "Timer Delay")
157:     public long getDelay() {
158:         return delay;
159:     }
160: 
161:     /**
162:      * The number of milliseconds to wait before the first event is generated. Should not be used in conjunction with
163:      * the time option.
164:      * <p/>
165:      * The default value is 1000.
166:      */
167:     @ManagedAttribute(description = "Timer Delay")
168:     public void setDelay(long delay) {
169:         this.delay = delay;
170:     }
171: 
172:     @ManagedAttribute(description = "Timer FixedRate")
173:     public boolean isFixedRate() {
174:         return fixedRate;
175:     }
176: 
177:     /**
178:      * Events take place at approximately regular intervals, separated by the specified period.
179:      */
180:     @ManagedAttribute(description = "Timer FixedRate")
181:     public void setFixedRate(boolean fixedRate) {
182:         this.fixedRate = fixedRate;
183:     }
184: 
185:     @ManagedAttribute(description = "The consumer logs a start/complete log line when it polls. This option allows you to configure the logging level for that.")
186:     public LoggingLevel getRunLoggingLevel() {
187:         return runLoggingLevel;
188:     }
189: 
190:     /**
191:      * The consumer logs a start/complete log line when it polls. This option allows you to configure the logging level
192:      * for that.
193:      */
194:     @ManagedAttribute(description = "The consumer logs a start/complete log line when it polls. This option allows you to configure the logging level for that.")
195:     public void setRunLoggingLevel(LoggingLevel runLoggingLevel) {
196:         this.runLoggingLevel = runLoggingLevel;
197:     }
198: 
199:     @ManagedAttribute(description = "Timer Period")
200:     public long getPeriod() {
201:         return period;
202:     }
203: 
204:     /**
205:      * Generate periodic events every period. Must be zero or positive value.
206:      * <p/>
207:      * The default value is 1000.
208:      */
209:     @ManagedAttribute(description = "Timer Period")
210:     public void setPeriod(long period) {
211:         this.period = period;
212:     }
213: 
214:     @ManagedAttribute(description = "Repeat Count")
215:     public long getRepeatCount() {
216:         return repeatCount;
217:     }
218: 
219:     /**
220:      * Specifies a maximum limit for the number of fires. Therefore, if you set it to 1, the timer will only fire once.
221:      * If you set it to 5, it will only fire five times. A value of zero or negative means fire forever.
222:      */
223:     @ManagedAttribute(description = "Repeat Count")
224:     public void setRepeatCount(long repeatCount) {
225:         this.repeatCount = repeatCount;
226:     }
227: 
228:     public Date getTime() {
229:         return time;
230:     }
231: 
232:     /**
233:      * A java.util.Date the first event should be generated. If using the URI, the pattern expected is: yyyy-MM-dd
234:      * HH:mm:ss or yyyy-MM-dd'T'HH:mm:ss.
235:      */
236:     public void setTime(Date time) {
237:         this.time = time;
238:     }
239: 
240:     public String getPattern() {
241:         return pattern;
242:     }
243: 
244:     /**
245:      * Allows you to specify a custom Date pattern to use for setting the time option using URI syntax.
246:      */
247:     public void setPattern(String pattern) {
248:         this.pattern = pattern;
249:     }
250: 
251:     public Timer getTimer() {
252:         return timer;
253:     }
254: 
255:     /**
256:      * To use a custom {@link Timer}
257:      */
258:     public void setTimer(Timer timer) {
259:         this.timer = timer;
260:     }
261: 
262:     public Timer getTimer(TimerConsumer consumer) {
263:         if (timer != null) {
264:             // use custom timer
265:             return timer;
266:         }
267:         return getComponent().getTimer(consumer);
268:     }
269: 
270:     @ManagedAttribute(description = "Include metadata")
271:     public boolean isIncludeMetadata() {
272:         return includeMetadata;
273:     }
274: 
275:     /**
276:      * Whether to include metadata in the exchange such as fired time, timer name, timer count etc.
277:      */
278:     @ManagedAttribute(description = "Include metadata")
279:     public void setIncludeMetadata(boolean includeMetadata) {
280:         this.includeMetadata = includeMetadata;
281:     }
282: 
283:     @ManagedAttribute(description = "Whether synchronous processing should be strictly used")
284:     public boolean isSynchronous() {
285:         return synchronous;
286:     }
287: 
288:     /**
289:      * Sets whether synchronous processing should be strictly used
290:      */
291:     public void setSynchronous(boolean synchronous) {
292:         this.synchronous = synchronous;
293:     }
294: 
295:     public void removeTimer(TimerConsumer consumer) {
296:         if (timer == null) {
297:             // only remove timer if we are not using a custom timer
298:             getComponent().removeTimer(consumer);
299:         }
300:     }
301: 
302: }
