17: package org.apache.camel.component.timer;
18: 
19: import java.util.Date;
20: import java.util.Timer;
21: import java.util.TimerTask;
22: import java.util.concurrent.ExecutorService;
23: import java.util.concurrent.atomic.AtomicLong;
24: 
25: import org.apache.camel.AsyncCallback;
26: import org.apache.camel.CamelContext;
27: import org.apache.camel.Exchange;
28: import org.apache.camel.LoggingLevel;
29: import org.apache.camel.Processor;
30: import org.apache.camel.StartupListener;
31: import org.apache.camel.Suspendable;
32: import org.apache.camel.api.management.ManagedAttribute;
33: import org.apache.camel.api.management.ManagedResource;
34: import org.apache.camel.support.DefaultConsumer;
35: import org.slf4j.Logger;
36: import org.slf4j.LoggerFactory;
37: 
38: /**
39:  * The timer consumer.
40:  */
41: @ManagedResource(description = "Managed TimerConsumer")
42: public class TimerConsumer extends DefaultConsumer implements StartupListener, Suspendable {
43: 
44:     private static final Logger LOG = LoggerFactory.getLogger(TimerConsumer.class);
45:     private final TimerEndpoint endpoint;
46:     private volatile TimerTask task;
47:     private volatile boolean configured;
48:     private ExecutorService executorService;
49:     private final AtomicLong counter = new AtomicLong();
50:     private volatile boolean polling;
51: 
52:     public TimerConsumer(TimerEndpoint endpoint, Processor processor) {
53:         super(endpoint, processor);
54:         this.endpoint = endpoint;
55:     }
56: 
57:     @Override
58:     public TimerEndpoint getEndpoint() {
59:         return (TimerEndpoint) super.getEndpoint();
60:     }
61: 
62:     /**
63:      * Total number of polls run
64:      */
65:     @ManagedAttribute(description = "Total number of polls run")
66:     public long getCounter() {
67:         return counter.get();
68:     }
69: 
70:     /**
71:      * Whether polling is currently in progress
72:      */
73:     @ManagedAttribute(description = "Whether polling is currently in progress")
74:     public boolean isPolling() {
75:         return polling;
76:     }
77: 
78:     @ManagedAttribute(description = "Timer Name")
79:     public String getTimerName() {
80:         return getEndpoint().getTimerName();
81:     }
82: 
83:     @ManagedAttribute(description = "Timer FixedRate")
84:     public boolean isFixedRate() {
85:         return getEndpoint().isFixedRate();
86:     }
87: 
88:     @ManagedAttribute(description = "Timer Delay")
89:     public long getDelay() {
90:         return getEndpoint().getDelay();
91:     }
92: 
93:     @ManagedAttribute(description = "Timer Period")
94:     public long getPeriod() {
95:         return getEndpoint().getPeriod();
96:     }
97: 
98:     @ManagedAttribute(description = "Repeat Count")
99:     public long getRepeatCount() {
100:         return getEndpoint().getRepeatCount();
101:     }
102: 
103:     @ManagedAttribute(description = "The consumer logs a start/complete log line when it polls. This option allows you to configure the logging level for that.")
104:     public String getRunLoggingLevel() {
105:         return getEndpoint().getRunLoggingLevel().name();
106:     }
107: 
108:     @Override
109:     public void doInit() throws Exception {
110:         if (endpoint.getDelay() >= 0) {
111:             task = new TimerTask() {
112:                 @Override
113:                 public void run() {
114:                     if (!isTaskRunAllowed()) {
115:                         // do not run timer task as it was not allowed
116:                         LOG.debug("Run not allowed for timer: {}", endpoint);
117:                         return;
118:                     }
119: 
120:                     // log starting
121:                     LoggingLevel runLoggingLevel = getEndpoint().getRunLoggingLevel();
122:                     if (LoggingLevel.ERROR == runLoggingLevel) {
123:                         LOG.error("Timer task started on:   {}", getEndpoint());
124:                     } else if (LoggingLevel.WARN == runLoggingLevel) {
125:                         LOG.warn("Timer task started on:   {}", getEndpoint());
126:                     } else if (LoggingLevel.INFO == runLoggingLevel) {
127:                         LOG.info("Timer task started on:   {}", getEndpoint());
128:                     } else if (LoggingLevel.DEBUG == runLoggingLevel) {
129:                         LOG.debug("Timer task started on:   {}", getEndpoint());
130:                     } else {
131:                         LOG.trace("Timer task started on:   {}", getEndpoint());
132:                     }
133: 
134:                     try {
135:                         polling = true;
136:                         doRun();
137:                     } catch (Exception e) {
138:                         LOG.warn(
139:                                 "Error processing exchange. This exception will be ignored, to let the timer be able to trigger again.",
140:                                 e);
141:                     } finally {
142:                         polling = false;
143:                     }
144: 
145:                     // log completed
146:                     if (LoggingLevel.ERROR == runLoggingLevel) {
147:                         LOG.error("Timer task completed on: {}", getEndpoint());
148:                     } else if (LoggingLevel.WARN == runLoggingLevel) {
149:                         LOG.warn("Timer task completed on: {}", getEndpoint());
150:                     } else if (LoggingLevel.INFO == runLoggingLevel) {
151:                         LOG.info("Timer task completed on: {}", getEndpoint());
152:                     } else if (LoggingLevel.DEBUG == runLoggingLevel) {
153:                         LOG.debug("Timer task completed on: {}", getEndpoint());
154:                     } else {
155:                         LOG.trace("Timer task completed on: {}", getEndpoint());
156:                     }
157:                 }
158: 
159:                 protected void doRun() {
160:                     long count = counter.incrementAndGet();
161: 
162:                     boolean fire = endpoint.getRepeatCount() <= 0 || count <= endpoint.getRepeatCount();
163:                     if (fire) {
164:                         sendTimerExchange(count);
165:                     } else {
166:                         // no need to fire anymore as we exceeded repeat
167:                         // count
168:                         LOG.debug("Cancelling {} timer as repeat count limit reached after {} counts.",
169:                                 endpoint.getTimerName(), endpoint.getRepeatCount());
170:                         cancel();
171:                     }
172:                 }
173:             };
174:         }
175:     }
176: 
177:     @Override
178:     protected void doStart() throws Exception {
179:         super.doStart();
180: 
181:         if (endpoint.getDelay() >= 0) {
182:             // only configure task if CamelContext already started, otherwise
183:             // the StartupListener is configuring the task later
184:             if (task != null && !configured && endpoint.getCamelContext().getStatus().isStarted()) {
185:                 Timer timer = endpoint.getTimer(this);
186:                 configureTask(task, timer);
187:             }
188:         } else {
189:             // if the delay is negative then we use an ExecutorService and fire messages as soon as possible
190:             executorService = endpoint.getCamelContext().getExecutorServiceManager().newSingleThreadExecutor(this,
191:                     endpoint.getEndpointUri());
192: 
193:             executorService.execute(() -> {
194:                 polling = true;
195:                 try {
196:                     long count = counter.incrementAndGet();
197:                     while ((endpoint.getRepeatCount() <= 0 || count <= endpoint.getRepeatCount()) && isRunAllowed()) {
198:                         sendTimerExchange(count);
199:                         count = counter.incrementAndGet();
200:                     }
201:                 } finally {
202:                     polling = false;
203:                 }
204:             });
205:         }
206:     }
207: 
208:     @Override
209:     protected void doStop() throws Exception {
210:         if (task != null) {
211:             task.cancel();
212:         }
213:         task = null;
214:         configured = false;
215: 
216:         // remove timer
217:         endpoint.removeTimer(this);
218: 
219:         // if executorService is instantiated then we shutdown it
220:         if (executorService != null) {
221:             endpoint.getCamelContext().getExecutorServiceManager().shutdown(executorService);
222:             executorService = null;
223:         }
224: 
225:         super.doStop();
226:     }
227: 
228:     @Override
229:     public void onCamelContextStarted(CamelContext context, boolean alreadyStarted) throws Exception {
230:         if (task != null && !configured) {
231:             Timer timer = endpoint.getTimer(this);
232:             configureTask(task, timer);
233:         }
234:     }
235: 
236:     /**
237:      * Whether the timer task is allow to run or not
238:      */
239:     protected boolean isTaskRunAllowed() {
240:         // only run if we are started
241:         return isStarted();
242:     }
243: 
244:     protected void configureTask(TimerTask task, Timer timer) {
245:         if (endpoint.isFixedRate()) {
246:             if (endpoint.getTime() != null) {
247:                 timer.scheduleAtFixedRate(task, endpoint.getTime(), endpoint.getPeriod());
248:             } else {
249:                 timer.scheduleAtFixedRate(task, endpoint.getDelay(), endpoint.getPeriod());
250:             }
251:         } else {
252:             if (endpoint.getTime() != null) {
253:                 if (endpoint.getPeriod() > 0) {
254:                     timer.schedule(task, endpoint.getTime(), endpoint.getPeriod());
255:                 } else {
256:                     timer.schedule(task, endpoint.getTime());
257:                 }
258:             } else {
259:                 if (endpoint.getPeriod() > 0) {
260:                     timer.schedule(task, endpoint.getDelay(), endpoint.getPeriod());
261:                 } else {
262:                     timer.schedule(task, endpoint.getDelay());
263:                 }
264:             }
265:         }
266:         configured = true;
267:     }
268: 
269:     protected void sendTimerExchange(long counter) {
270:         final Exchange exchange = createExchange(false);
271: 
272:         if (endpoint.isIncludeMetadata()) {
273:             exchange.setProperty(Exchange.TIMER_COUNTER, counter);
274:             exchange.setProperty(Exchange.TIMER_NAME, endpoint.getTimerName());
275:             if (endpoint.getTime() != null) {
276:                 exchange.setProperty(Exchange.TIMER_TIME, endpoint.getTime());
277:             }
278:             exchange.setProperty(Exchange.TIMER_PERIOD, endpoint.getPeriod());
279: 
280:             Date now = new Date();
281:             exchange.setProperty(TimerConstants.HEADER_FIRED_TIME, now);
282:             exchange.getIn().setHeader(TimerConstants.HEADER_FIRED_TIME, now);
283:             exchange.getIn().setHeader(TimerConstants.HEADER_MESSAGE_TIMESTAMP, now.getTime());
284:         }
285: 
286:         if (LOG.isTraceEnabled()) {
287:             LOG.trace("Timer {} is firing #{} count", endpoint.getTimerName(), counter);
288:         }
289: 
290:         if (!endpoint.isSynchronous()) {
291:             // use default consumer callback
292:             AsyncCallback cb = defaultConsumerCallback(exchange, false);
293:             getAsyncProcessor().process(exchange, cb);
294:         } else {
295:             try {
296:                 getProcessor().process(exchange);
297:             } catch (Exception e) {
298:                 exchange.setException(e);
299:             }
300: 
301:             // handle any thrown exception
302:             try {
303:                 if (exchange.getException() != null) {
304:                     getExceptionHandler().handleException("Error processing exchange", exchange, exchange.getException());
305:                 }
306:             } finally {
307:                 releaseExchange(exchange, false);
308:             }
309:         }
310:     }
311: }
