package org.apache.camel.component.fix;

import java.util.Map;

import org.apache.camel.Endpoint;
import org.apache.camel.spi.Metadata;
import org.apache.camel.spi.annotations.Component;
import org.apache.camel.support.DefaultComponent;

/**
 * The FIX component manages {@link FixEndpoint} and holds shared FIX engine lifecycle.
 *
 * FIX (Financial Information eXchange) is the standard electronic messaging protocol for securities trading.
 */
@Component("fix")
public class FixComponent extends DefaultComponent {

    @Metadata(label = "advanced", description = "Global default FIX configuration")
    private FixConfiguration configuration = new FixConfiguration();

    public FixComponent() {
    }

    @Override
    protected Endpoint createEndpoint(String uri, String remaining, Map<String, Object> parameters) throws Exception {
        FixEndpoint endpoint = new FixEndpoint(uri, this);

        // Set the session ID from the URI
        endpoint.setSessionID(remaining);

        // Clone the configuration and apply it to the endpoint
        FixConfiguration config = configuration.clone();

        // Apply any parameters
        setProperties(config, parameters);

        // Set the configuration on the endpoint
        endpoint.setConfiguration(config);

        // Also set any remaining parameters on the endpoint
        setProperties(endpoint, parameters);

        return endpoint;
    }

    @Override
    protected void doStart() throws Exception {
        super.doStart();
        // Initialize shared FIX engine if needed
    }

    @Override
    protected void doStop() throws Exception {
        // Cleanup FIX engine
        super.doStop();
    }

    public FixConfiguration getConfiguration() {
        return configuration;
    }

    /**
     * Global default FIX configuration
     */
    public void setConfiguration(FixConfiguration configuration) {
        this.configuration = configuration;
    }
}

